1	export type Cell = [number, number];
2	
3	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [ 0, -1],          [ 0, 1],
8	  [ 1, -1], [ 1, 0], [ 1, 1],
9	];
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const countLiveNeighbors = (cell: Cell, liveSet: ReadonlySet<string>): number =>
15	  neighborsOf(cell).filter((n) => liveSet.has(cellKey(n))).length;
16	
17	const survivesToNextGeneration = (cell: Cell, liveSet: ReadonlySet<string>): boolean => {
18	  const n = countLiveNeighbors(cell, liveSet);
19	  return liveSet.has(cellKey(cell)) ? n === 2 || n === 3 : n === 3;
20	};
21	
22	export function nextGeneration(liveCells: readonly Cell[]): Cell[] {
23	  const liveSet = new Set(liveCells.map(cellKey));
24	
25	  const candidates = new Map<string, Cell>();
26	  for (const cell of liveCells) {
27	    for (const candidate of [cell, ...neighborsOf(cell)]) {
28	      candidates.set(cellKey(candidate), candidate);
29	    }
30	  }
31	
32	  return [...candidates.values()].filter((cell) => survivesToNextGeneration(cell, liveSet));
33	}
